import base64

b64_raw = ""

try:
    decoded = base64.b64decode(b64_raw).decode('utf-8')
    print("UTF-8 Success!")
    print(decoded[:100])
except Exception as e:
    print(f"UTF-8 Failed: {e}")
    try:
        decoded = base64.b64decode(b64_raw).decode('latin-1')
        print("Latin-1 Success!")
        print(decoded[:100])
    except Exception as e2:
        print(f"Latin-1 Failed: {e2}")
